import{_ as a,o as s,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Local Config File","description":"","frontmatter":{},"headers":[],"relativePath":"settings/local-file-config.md","filePath":"settings/local-file-config.md","lastUpdated":1782688753000}'),o={name:"settings/local-file-config.md"};function n(l,e,r,p,d,c){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="local-config-file" tabindex="-1">Local Config File <a class="header-anchor" href="#local-config-file" aria-label="Permalink to &quot;Local Config File&quot;">​</a></h1><p>EasyYapi uses <code>.easy.api.config</code> files as local configuration files. Starting with EasyYapi 3.0, the recommended approach is the <a href="./rule-authoring#folder-based-rule-files"><code>.easyapi/</code> folder model</a>, where every regular file in <code>.easyapi/</code> is loaded automatically. The legacy <code>.easy.api.config*</code> files below are still read for backwards compatibility.</p><h2 id="file-location" tabindex="-1">File Location <a class="header-anchor" href="#file-location" aria-label="Permalink to &quot;File Location&quot;">​</a></h2><p>Rule files are resolved from the <strong>IntelliJ project base path</strong> — the folder you opened in the IDE (<code>project.basePath</code>). Discovery never walks <em>down</em> into child directories, so config files placed in nested module folders are <strong>not</strong> loaded when the parent is opened as the project.</p><blockquote><p><strong>Heads-up for multi-module projects:</strong> there is no per-module config tier. If you open <code>your-project/</code> as the project, only <code>.easy.api.config</code> / <code>.easyapi/</code> at <code>your-project/</code> and its <em>ancestor</em> directories are read. To give a single module its own rules, open that module&#39;s folder as its own IntelliJ project, or keep everything in the shared <code>&lt;project&gt;/.easyapi/</code> folder.</p></blockquote><h3 id="project-root" tabindex="-1">Project Root <a class="header-anchor" href="#project-root" aria-label="Permalink to &quot;Project Root&quot;">​</a></h3><p>The folder you opened in the IDE:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>your-project/</span></span>
<span class="line"><span>├── .easy.api.config</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>└── pom.xml</span></span></code></pre></div><p>Legacy <code>.easy.api.config[.properties|.yml|.yaml]</code> files are also picked up by walking <strong>up</strong> from the project base to its ancestors (e.g. a config in a parent directory shared by several projects).</p><h3 id="_3-0-folder-model-recommended" tabindex="-1">3.0+ Folder Model (recommended) <a class="header-anchor" href="#_3-0-folder-model-recommended" aria-label="Permalink to &quot;3.0+ Folder Model (recommended)&quot;">​</a></h3><p>Place any number of <code>.rules</code> (or <code>.properties</code>) files in the <code>.easyapi/</code> folder. Every regular file is loaded — no list to maintain.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>your-project/</span></span>
<span class="line"><span>├── .easyapi/</span></span>
<span class="line"><span>│   ├── naming.rules</span></span>
<span class="line"><span>│   ├── security.rules</span></span>
<span class="line"><span>│   └── postman.rules</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>└── pom.xml</span></span></code></pre></div><p>The same model applies at the global scope: <code>~/.easyapi/*.rules</code> is loaded for every project on the machine. Manage files visually in <strong>Settings → EasyApi → Rules</strong> (Project / Global / Remote sub-tabs).</p><h2 id="file-format" tabindex="-1">File Format <a class="header-anchor" href="#file-format" aria-label="Permalink to &quot;File Format&quot;">​</a></h2><p>The config file uses <code>key=value</code> format:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Comments start with #</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># API name rule</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">api.name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#name</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Field ignore rule</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">field.ignore</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.hasAnn(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.fasterxml.jackson.annotation.JsonIgnore&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Type conversion</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">json.rule.convert</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.type().name()==</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;java.util.Date&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> =&gt; java.lang.String</span></span></code></pre></div><h2 id="config-merging" tabindex="-1">Config Merging <a class="header-anchor" href="#config-merging" aria-label="Permalink to &quot;Config Merging&quot;">​</a></h2><p>Configuration is merged from several sources by priority. Within the same source, files in <code>.easyapi/</code> are read in sorted name order and appended in sequence. Higher-priority sources override lower-priority ones for the same key.</p><table tabindex="0"><thead><tr><th style="text-align:center;">Priority</th><th>Source</th><th>Loaded from</th></tr></thead><tbody><tr><td style="text-align:center;">4</td><td><strong>Project rules</strong></td><td><code>&lt;project&gt;/.easyapi/*</code> (all regular files) + legacy <code>.easy.api.config*</code> walked up from <code>&lt;project&gt;</code></td></tr><tr><td style="text-align:center;">3</td><td>Extension rules</td><td>Bundled framework presets (Spring, Jackson, Validation, Swagger, …) toggleable in Settings → Extensions</td></tr><tr><td style="text-align:center;">3</td><td>Remote rules</td><td>URLs from <code>remote.url</code> (Settings → Rules → Remote)</td></tr><tr><td style="text-align:center;">2</td><td>Global rules</td><td><code>~/.easyapi/*</code> (all regular files)</td></tr></tbody></table><p>Project rules win over everything else; global rules are the lowest-tier fallback. There is no separate module-level tier.</p>`,20)])])}const u=a(o,[["render",n]]);export{g as __pageData,u as default};
